import React, { useState } from "react";
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';

const LOGO_IMG = "data:image/png;base64,";
const LOGO_IMG_DARK = "data:image/png;base64,";
const HERO_IMG = "data:image/png;base64,";

export function LoginPage({ onLogin }: { onLogin: () => void }) {
  const [showPassword, setShowPassword] = useState(false);
  const [remember, setRemember] = useState(true);
  const [theme, setTheme] = useState<"light" | "dark">("light");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [errorMsg, setErrorMsg] = useState("");
  const [loading, setLoading] = useState(false);
  
  const auth = useAuth();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg('');
    setLoading(true);

    try {
      const response = await api.post('auth/login/', { email, password });
      if (response.data.access && response.data.refresh) {
        await auth.login(response.data.access, response.data.refresh);
        onLogin();
      } else {
        setErrorMsg('Réponse inattendue du serveur.');
      }
    } catch (err: any) {
      console.error(err);
      if (err.response && err.response.data && err.response.data.detail) {
        setErrorMsg(err.response.data.detail);
      } else {
        setErrorMsg('Identifiants incorrects ou serveur injoignable.');
      }
    } finally {
      setLoading(false);
    }
  };

  const isDark = theme === "dark";
  const iconStroke = isDark ? "#9c9b97" : "#8a8a86";
  const logoSrc = isDark ? LOGO_IMG_DARK : LOGO_IMG;

  const darkOverrides: { [key: string]: React.CSSProperties } = {
    body: { background: "#101114" },
    card: {
      background: "#131418",
      border: "1px solid rgba(255,255,255,0.08)",
      boxShadow: "0 3vh 6vh -1.6vh rgba(0,0,0,.55)",
    },
    cardTitle: { color: "#f7f5f2" },
    headline: { color: "#f7f5f2" },
    subhead: { color: "#9a9a95" },
    brandName: { color: "#f7f5f2" },
    brandSep: { background: "#3a3a38" },
    label: { color: "#f0efec" },
    inputBox: { background: "#17181c", border: "1.5px solid rgba(255,255,255,0.14)" },
    input: { color: "#f2f1ee" },
    trustTitle: { color: "#f0efec" },
    trustSub: { color: "#9a9a95" },
    trustIcon: {
      border: "1px solid rgba(255,255,255,.18)",
      background: "rgba(255,255,255,.05)",
      color: "#f0efec",
    },
    divider: { color: "#77766f" },
    dividerLine: { background: "rgba(255,255,255,.12)" },
    oauthBtn: {
      background: "#17181c",
      border: "1.5px solid rgba(255,255,255,.14)",
      color: "#e4e3df",
    },
    cardFooter: { color: "#66655f" },
    btnLogin: { background: "linear-gradient(90deg,#f2a93b 0%,#ea7245 55%,#d95a35 100%)" },
    arrowCircle: { background: "#f7ab8e" },
    themeToggle: { background: "#1c1e22" },
    themeBtn: { color: "#c9c8c3" },
    heroBlob: {
      background: "linear-gradient(160deg,#1c1d20 0%,#17181b 55%,#131417 100%)",
    },
    decoTopCircleOutline: { border: "1px solid rgba(242,169,59,0.25)" },
    decoTopFill: { background: "rgba(242,130,80,0.1)", opacity: 1 },
    decoDotTop: { background: "#f2a93b" },
    decoDot: { background: "rgba(255,255,255,.15)" },
    decoOrangeCircle: { background: "#e2622f" },
    decoRingMid: { border: "1px solid rgba(242,169,59,0.2)" },
    decoBottomBlob: { background: "rgba(255,150,60,0.05)" },
    decoRightRing: { border: "1px solid rgba(242,169,59,.2)" },
  };

  function s(key: string): React.CSSProperties {
    return { ...styles[key], ...(isDark ? darkOverrides[key] : {}) };
  }

  return (
    <div className="aod-root" style={s('body')}>
      <style>{`
        @keyframes fadeIn { from { opacity: 0; transform: translateY(8px);} to { opacity: 1; transform: translateY(0);} }
        .aod-input::placeholder { color: ${isDark ? "#63625f" : "#a9a8a3"}; }
        .aod-input:focus { outline: none; }
        .aod-input-box:focus-within { border-color: #f2a97a; box-shadow: 0 0 0 3px rgba(242,130,80,0.12); }
        .aod-forgot:hover { text-decoration: underline; }
        .aod-oauth-btn:hover { background: ${isDark ? "#1e2024" : "#faf9f6"}; }
        .aod-login-btn:hover { ${isDark ? "filter: brightness(1.08);" : "background: #000000;"} }
        .aod-theme-btn { cursor: pointer; border: none; }
        @media (max-width: 1100px), (max-height: 650px) {
          html, body { overflow-y: auto !important; }
          .aod-root { height: auto !important; overflow: visible !important; }
          .aod-page { height: auto !important; min-height: 100vh; flex-direction: column; padding: 30px 24px !important; overflow: visible !important; }
          .aod-left-panel { text-align: center; }
          .aod-brand { justify-content: center; }
          .aod-rule { margin-left: auto; margin-right: auto; }
          .aod-subhead { margin-left: auto; margin-right: auto; }
          .aod-headline { font-size: 52px !important; }
          .aod-trust-badge { justify-content: center; }
          .aod-theme-toggle { top: 20px !important; right: 24px !important; }
        }
        @media (max-width: 560px) {
          .aod-card { padding: 32px 24px 26px !important; }
          .aod-headline { font-size: 40px !important; }
        }
      `}</style>

      <div className="aod-page" style={s('page')}>
        {/* Decorative background shapes */}
        <div style={s('decoTopCircleOutline')} />
        <div style={s('decoTopFill')} />
        <div style={s('decoDotTop')} />
        <div style={s('decoDotsGrid')}>
          {Array.from({ length: 16 }).map((_, i) => (
            <span key={i} style={s('decoDot')} />
          ))}
        </div>
        <div style={s('decoOrangeCircle')} />
        <div style={s('decoRingMid')} />
        <div style={s('decoBottomBlob')} />
        <div style={s('decoRightRing')} />

        {/* Theme toggle */}
        <div className="aod-theme-toggle" style={s('themeToggle')}>
          <button
            className="aod-theme-btn"
            aria-label="Mode sombre"
            onClick={() => setTheme("dark")}
            style={{
              ...styles.themeBtn,
              ...(theme === "dark" ? styles.themeBtnActive : {}),
            }}
          >
            <svg width="17" height="17" viewBox="0 0 24 24" fill="currentColor">
              <path d="M12 3a9 9 0 1 0 9 9c0-.46-.04-.92-.1-1.36a5.389 5.389 0 0 1-4.4 2.26 5.403 5.403 0 0 1-3.14-9.8c-.44-.06-.9-.1-1.36-.1z" />
            </svg>
          </button>
          <button
            className="aod-theme-btn"
            aria-label="Mode clair"
            onClick={() => setTheme("light")}
            style={{
              ...styles.themeBtn,
              ...(theme === "light" ? styles.themeBtnActive : {}),
            }}
          >
            <svg width="17" height="17" viewBox="0 0 24 24" fill="currentColor">
              <circle cx="12" cy="12" r="5" />
              <path
                d="M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
              />
            </svg>
          </button>
        </div>

        {/* Left content */}
        <div className="aod-left-panel" style={s('leftPanel')}>
          <div className="aod-brand" style={s('brand')}>
            <img src={logoSrc} alt="AgrOdiv" style={s('brandLogo')} />
            <span style={s('brandName')}>AgrOdiv</span>
            <span style={s('brandSep')} />
            <span style={s('brandTag')}>GED</span>
          </div>

          <h1 className="aod-headline" style={s('headline')}>
            Bienvenue<span style={{ color: "#ea7245" }}>.</span>
          </h1>
          <p className="aod-subhead" style={s('subhead')}>
            Connectez-vous pour accéder à votre espace documentaire.
          </p>
          <div className="aod-rule" style={s('rule')} />

          <div style={s('heroImageWrap')}>
            <div style={s('heroBlob')}>
              <img
                src={HERO_IMG}
                alt="Espace de bureau organisé avec ordinateur, classeurs et documents"
                style={s('heroImg')}
              />
            </div>
          </div>

          <div className="aod-trust-badge" style={s('trustBadge')}>
            <div style={s('trustIcon')}>
              <svg width="23" height="23" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
                <path d="M12 2l8 3v6c0 5-3.4 8.4-8 11-4.6-2.6-8-6-8-11V5l8-3z" />
                <path d="M9 12l2 2 4-4" />
              </svg>
            </div>
            <div>
              <div style={s('trustTitle')}>Sécurisé. Organisé. Fiable.</div>
              <div style={s('trustSub')}>Vos documents, notre priorité.</div>
            </div>
          </div>
        </div>

        {/* Login card */}
        <div style={s('cardWrap')}>
          <div className="aod-card" style={s('card')}>
            <div style={s('cardLogoWrap')}>
              <img src={logoSrc} alt="AgrOdiv" style={s('cardLogo')} />
            </div>
            <h2 style={s('cardTitle')}>
              Gestion Electronique
              <br />
              des <span style={{ color: "#ea7245" }}>Documents</span>
            </h2>

            <form onSubmit={handleSubmit}>
              {errorMsg && (
                <div style={{ color: '#ea7245', marginBottom: '1rem', fontSize: '0.875rem' }}>
                  {errorMsg}
                </div>
              )}
              <div style={s('field')}>
                <label htmlFor="email" style={s('label')}>
                  Email
                </label>
                <div className="aod-input-box" style={s('inputBox')}>
                  <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke={iconStroke} strokeWidth="1.8">
                    <rect x="2" y="4" width="20" height="16" rx="2" />
                    <path d="M2 6l10 7 10-7" />
                  </svg>
                  <input
                    id="email"
                    type="email"
                    className="aod-input"
                    placeholder="Entrez votre adresse email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    style={s('input')}
                    required
                  />
                </div>
              </div>

              <div style={s('field')}>
                <label htmlFor="password" style={s('label')}>
                  Mot de passe
                </label>
                <div className="aod-input-box" style={s('inputBox')}>
                  <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke={iconStroke} strokeWidth="1.8">
                    <rect x="4" y="10" width="16" height="10" rx="2" />
                    <path d="M8 10V7a4 4 0 0 1 8 0v3" />
                  </svg>
                  <input
                    id="password"
                    type={showPassword ? "text" : "password"}
                    className="aod-input"
                    placeholder="Entrez votre mot de passe"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    style={s('input')}
                    required
                  />
                  <button
                    type="button"
                    aria-label="Afficher le mot de passe"
                    onClick={() => setShowPassword((s) => !s)}
                    style={s('eyeBtn')}
                  >
                    {showPassword ? (
                      <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke={iconStroke} strokeWidth="1.8">
                        <path d="M17.94 17.94A10.94 10.94 0 0 1 12 19c-7 0-11-7-11-7a21.6 21.6 0 0 1 5.06-6.06M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 7 11 7a21.6 21.6 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24" />
                        <line x1="1" y1="1" x2="23" y2="23" />
                      </svg>
                    ) : (
                      <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke={iconStroke} strokeWidth="1.8">
                        <path d="M1 12s4-7 11-7 11 7 11 7-4 7-11 7-11-7-11-7z" />
                        <circle cx="12" cy="12" r="3" />
                      </svg>
                    )}
                  </button>
                </div>
              </div>

              <div style={s('rowBetween')}>
                <label style={s('remember')}>
                  <input
                    type="checkbox"
                    checked={remember}
                    onChange={(e) => setRemember(e.target.checked)}
                    style={s('checkbox')}
                  />
                  Se souvenir de moi
                </label>
                <a href="#" className="aod-forgot" style={s('forgot')}>
                  Mot de passe oublié ?
                </a>
              </div>

              <button type="submit" className="aod-login-btn" style={s('btnLogin')} disabled={loading}>
                {loading ? 'Connexion en cours...' : 'Se connecter'}
                <span style={s('arrowCircle')}>
                  <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="#1a1a1a" strokeWidth="2.2">
                    <path d="M5 12h14M13 6l6 6-6 6" />
                  </svg>
                </span>
              </button>
            </form>

            <div style={s('divider')}>
              <span style={s('dividerLine')} />
              <span>Ou continuer avec</span>
              <span style={s('dividerLine')} />
            </div>

            <div style={s('oauthRow')}>
              <button className="aod-oauth-btn" type="button" style={s('oauthBtn')}>
                <svg width="19" height="19" viewBox="0 0 24 24">
                  <path fill="#4285F4" d="M23.52 12.27c0-.85-.08-1.66-.22-2.44H12v4.62h6.47c-.28 1.5-1.13 2.77-2.4 3.62v3h3.89c2.28-2.1 3.56-5.2 3.56-8.8z" />
                  <path fill="#34A853" d="M12 24c3.24 0 5.96-1.07 7.95-2.9l-3.89-3c-1.08.73-2.46 1.16-4.06 1.16-3.12 0-5.77-2.11-6.72-4.94H1.27v3.1C3.25 21.3 7.31 24 12 24z" />
                  <path fill="#FBBC05" d="M5.28 14.32c-.24-.73-.38-1.5-.38-2.32s.14-1.59.38-2.32V6.58H1.27C.46 8.17 0 9.99 0 12s.46 3.83 1.27 5.42l4.01-3.1z" />
                  <path fill="#EA4335" d="M12 4.75c1.77 0 3.35.61 4.6 1.8l3.45-3.45C17.95 1.19 15.24 0 12 0 7.31 0 3.25 2.7 1.27 6.58l4.01 3.1c.95-2.83 3.6-4.93 6.72-4.93z" />
                </svg>
                Google
              </button>
              <button className="aod-oauth-btn" type="button" style={s('oauthBtn')}>
                <svg width="19" height="19" viewBox="0 0 24 24">
                  <rect x="1" y="1" width="10" height="10" fill="#F25022" />
                  <rect x="13" y="1" width="10" height="10" fill="#7FBA00" />
                  <rect x="1" y="13" width="10" height="10" fill="#00A4EF" />
                  <rect x="13" y="13" width="10" height="10" fill="#FFB900" />
                </svg>
                Microsoft
              </button>
            </div>

            <div style={s('cardFooter')}>
              Version 2.0.0 &nbsp;•&nbsp; AgrOdiv © 2024 Tous droits réservés
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

