  card: {
    background: CARD_BG,
    width: "36.5vw",
    minWidth: 410,
    maxWidth: "92vw",
    borderRadius: "2.71vh",
    padding: "4.55vh 3.9vw 3.55vh",
    boxShadow: "0 3vh 6vh -1.6vh rgba(0,0,0,.18)",
  },
